#include<bits/stdc++.h>
using namespace std;
int a[100005];
int f[100005][25];
int d[100005],n,q;
int dfs(int x){
    if(a[x]!=0) return a[x];
    if(x==0){
        return a[x]=0;
    }else{

        return a[x]=max(x,dfs(f[x][0]));
    }
}
int dfs2(int x){
    if(d[x]!=0) return d[x];
    if(x==0){
        return d[x]=0;
    }else{

        return d[x]=dfs2(f[x][0])+1;
    }
}
int lca(int x,int y){
    if(d[x] < d[y]) swap(x, y);
    int z = d[x] - d[y];
    for(int i=0; i<=20; i++) {
        if(z >> i & 1) x = f[x][i];
    }
    if(x == y) return x;
   for(int i=20; i>=0; i--) {
        if(f[x][i] != f[y][i]) {
            x = f[x][i];
            y = f[y][i];
        }
    }
    return f[x][0];
}
int main(){
    cin>>n;
    f[0][0]=0;
    d[0]=0;
    for(int i=1;i<n;i++){
        cin>>f[i][0];
    }
     for(int i=1;i<n;i++){
        d[i]=dfs2(i);
    }
    for(int i=1;i<n;i++){
        a[i]=dfs(i);
    }

    for(int i=1;i<=20;i++){
        for(int j=0;j<n;j++){
            f[j][i]=f[f[j][i-1]][i-1];
        }
    }
    cin>>q;
    for(int i=1;i<=q;i++){
        int m;
        cin>>m;
        int x,y;
        cin>>x;
        for(int j=2;j<=m;j++){
            cin>>y;
            x=lca(x,y);
        }
        cout<<a[x]<<"\n";
    }
    return 0;
}
